#include "st7789_tft.h"
#include <SPI.h>
#include <Adafruit_GFX.h>
static Adafruit_ST7789 tft(5,16,17);
void st7789_setup(){tft.init(240,240);tft.setRotation(2);tft.fillScreen(ST77XX_BLACK);Serial.println("[st7789] OK 240x240");}
void st7789_clear(uint16_t c){tft.fillScreen(c);}
void st7789_text(int x,int y,const char*t,uint16_t c,int s){tft.setCursor(x,y);tft.setTextColor(c);tft.setTextSize(s);tft.print(t);}
void st7789_fill_rect(int x,int y,int w,int h,uint16_t c){tft.fillRect(x,y,w,h,c);}
